 1	import React, { FC } from 'react';
 2	
 3	import { getName } from '@kubevirt-utils/resources/shared';
 4	import { useQuickStartContext } from '@openshift-console/dynamic-plugin-sdk';
 5	import {
 6	  QuickStart,
 7	  QuickStartContextProvider,
 8	  useValuesForQuickStartContext,
 9	} from '@patternfly/quickstarts';
10	import { Button, ButtonVariant } from '@patternfly/react-core';
11	
12	import { GettingStartedLink } from '../../../../../../../clusteroverview/OverviewTab/getting-started-card/utils/types';
13	
14	import './QuickStartLauncherLink.scss';
15	
16	type QuickStartLauncherLinkProps = {
17	  quickStart: QuickStart;
18	  quickStartLoaded: boolean;
19	  text: string;
20	};
21	
22	const QuickStartLauncherLink: FC<QuickStartLauncherLinkProps> = ({
23	  quickStart,
24	  quickStartLoaded,
25	  text,
26	}) => {
27	  const quickStartValues = useValuesForQuickStartContext();
28	  const { setActiveQuickStart } = useQuickStartContext();
29	
30	  const quickStartLink: GettingStartedLink = quickStartLoaded && {
31	    id: getName(quickStart),
32	    onClick: () => {
33	      setActiveQuickStart(quickStart.metadata.name, quickStart?.spec?.tasks?.length);
34	    },
35	    title: quickStart?.spec?.displayName,
36	  };
37	
38	  const handleClick = quickStartLink.onClick;
39	
40	  return (
41	    <QuickStartContextProvider value={quickStartValues}>
42	      <Button
43	        className="quick-start-launcher-link"
44	        onClick={handleClick}
45	        variant={ButtonVariant.link}
46	      >
47	        {text}
48	      </Button>
49	    </QuickStartContextProvider>
50	  );
51	};
52	
53	export default QuickStartLauncherLink;

